1	/**
2	 * Finalizer.
3	 *
4	 * Aggregates chunk analyses into a complete report.
5	 * This is the most important step — it synthesizes everything
6	 * into a coherent, actionable output.
7	 */
8	
9	import type { Session } from "../types/session.js";
10	import type { SessionEvent, FileWriteEvent, FileReadEvent, SearchEvent } from "../types/events.js";
11	import type { ChunkAnalysis, FrictionCategory, PhaseType } from "../types/chunks.js";
12	import type {
13	  Report,
14	  EffortBreakdown,
15	  KeySignals,
16	  FrictionAnalysis,
17	  FrictionItem,
18	  Evidence,
19	  Recommendation,
20	  GitContext,
21	} from "../types/report.js";
22	
23	export function finalize(
24	  session: Session,
25	  chunkAnalyses: ChunkAnalysis[],
26	  events: SessionEvent[],
27	  gitContext: GitContext
28	): Report {
29	  return {
30	    taskSummary: buildTaskSummary(session, chunkAnalyses),
31	    effortBreakdown: buildEffortBreakdown(chunkAnalyses),
32	    keySignals: buildKeySignals(events),
33	    frictionAnalysis: buildFrictionAnalysis(chunkAnalyses, events),
34	    evidence: buildEvidence(chunkAnalyses),
35	    recommendations: buildRecommendations(chunkAnalyses, events),
36	    chunks: chunkAnalyses,
37	    gitContext,
38	    metadata: {
39	      generatedAt: new Date().toISOString(),
40	      beaverVersion: "0.1.0",
41	      sessionProvider: session.provider,
42	      analysisMode: "heuristic",
43	    },
44	  };
45	}
46	
47	// --- Task summary ---
48	
49	function buildTaskSummary(
50	  session: Session,
51	  chunks: ChunkAnalysis[]
52	): string {
53	  const totalEvents = chunks.reduce((sum, c) => sum + c.eventCount, 0);
54	  const phases = chunks.map((c) => c.phase).join(" → ");
55	  const duration = session.metadata.durationMs
56	    ? formatDuration(session.metadata.durationMs)
57	    : "unknown duration";
58	
59	  // Try to extract task description from first user message
60	  const firstUserMsg = session.messages.find((m) => m.role === "user");
61	  const taskHint = firstUserMsg
62	    ? truncate(firstUserMsg.content, 120)
63	    : "Unknown task";
64	
65	  return [
66	    `Task: ${taskHint}`,
67	    `Session: ${totalEvents} events across ${chunks.length} phase(s) (${phases})`,
68	    `Duration: ${duration}`,
69	    `Model: ${session.metadata.model || "unknown"}`,
70	    `Tool calls: ${session.metadata.totalToolCalls}`,
71	  ].join("\n");
72	}
73	
74	// --- Effort breakdown ---
75	
76	function buildEffortBreakdown(chunks: ChunkAnalysis[]): EffortBreakdown {
77	  const totals: Record<PhaseType, number> = {
78	    exploration: 0,
79	    implementation: 0,
80	    debugging: 0,
81	    verification: 0,
82	  };
83	
84	  const totalEvents = chunks.reduce((sum, c) => sum + c.eventCount, 0);
85	
86	  for (const chunk of chunks) {
87	    totals[chunk.phase] += chunk.eventCount;
88	  }
89	
90	  // Normalize to percentages
91	  if (totalEvents === 0) {
92	    return { exploration: 25, implementation: 25, debugging: 25, verification: 25 };
93	  }
94	
95	  return {
96	    exploration: Math.round((totals.exploration / totalEvents) * 100),
97	    implementation: Math.round((totals.implementation / totalEvents) * 100),
98	    debugging: Math.round((totals.debugging / totalEvents) * 100),
99	    verification: Math.round((totals.verification / totalEvents) * 100),
100	  };
101	}
102	
103	// --- Key signals ---
104	
105	function buildKeySignals(events: SessionEvent[]): KeySignals {
106	  const files = new Set<string>();
107	  let filesRead = 0;
108	  let filesWritten = 0;
109	  let searches = 0;
110	  let edits = 0;
111	  let retries = 0;
112	  let testRuns = 0;
113	  let commands = 0;
114	
115	  for (const event of events) {
116	    const data = event.data as Record<string, unknown>;
117	    const path = typeof data.path === "string" ? data.path : "";
118	
119	    switch (event.type) {
120	      case "file_read":
121	        filesRead++;
122	        if (path) files.add(path);
123	        break;
124	      case "file_write":
125	        filesWritten++;
126	        edits++;
127	        if (path) files.add(path);
128	        break;
129	      case "search":
130	        searches++;
131	        break;
132	      case "test_run":
133	        testRuns++;
134	        break;
135	      case "command_run":
136	        commands++;
137	        break;
138	      case "retry":
139	        retries++;
140	        break;
141	    }
142	  }
143	
144	  return {
145	    filesRead,
146	    filesWritten,
147	    searches,
148	    edits,
149	    retries,
150	    testRuns,
151	    commands,
152	    uniqueFilesTouched: Array.from(files),
153	  };
154	}
155	
156	// --- Friction analysis ---
157	
158	function buildFrictionAnalysis(
159	  chunks: ChunkAnalysis[],
160	  events: SessionEvent[]
161	): FrictionAnalysis {
162	  // Count friction categories across all chunks
163	  const frictionCounts = new Map<FrictionCategory, number>();
164	  const frictionEvidence = new Map<FrictionCategory, string[]>();
165	
166	  for (const chunk of chunks) {
167	    for (const friction of chunk.frictionClassification) {
168	      frictionCounts.set(friction, (frictionCounts.get(friction) || 0) + 1);
169	
170	      if (!frictionEvidence.has(friction)) {
171	        frictionEvidence.set(friction, []);
172	      }
173	      frictionEvidence.get(friction)!.push(
174	        `Detected in ${chunk.phase} phase: ${chunk.summary}`
175	      );
176	    }
177	  }
178	
179	  // Add pattern-based friction evidence
180	  for (const chunk of chunks) {
181	    for (const pattern of chunk.patterns) {
182	      for (const friction of chunk.frictionClassification) {
183	        frictionEvidence.get(friction)?.push(pattern);
184	      }
185	    }
186	  }
187	
188	  // Sort by frequency
189	  const sorted = Array.from(frictionCounts.entries())
190	    .sort((a, b) => b[1] - a[1]);
191	
192	  if (sorted.length === 0) {
193	    // No friction detected - this is good!
194	    return {
195	      primary: {
196	        category: "discovery_friction",
197	        description: "No significant friction detected. Session ran smoothly.",
198	        severity: "low",
199	        evidence: ["All phases completed without notable friction signals."],
200	      },
201	      secondary: [],
202	    };
203	  }
204	
205	  const primary = sorted[0];
206	  const secondary = sorted.slice(1);
207	
208	  return {
209	    primary: {
210	      category: primary[0],
211	      description: describeFriction(primary[0]),
212	      severity: primary[1] > 2 ? "high" : primary[1] > 1 ? "medium" : "low",
213	      evidence: frictionEvidence.get(primary[0]) || [],
214	    },
215	    secondary: secondary.map(([cat, count]) => ({
216	      category: cat,
217	      description: describeFriction(cat),
218	      severity: (count > 2 ? "high" : count > 1 ? "medium" : "low") as "high" | "medium" | "low",
219	      evidence: frictionEvidence.get(cat) || [],
220	    })),
221	  };
222	}
223	
224	function describeFriction(category: FrictionCategory): string {
225	  const descriptions: Record<FrictionCategory, string> = {
226	    discovery_friction:
227	      "Agent spent significant effort finding relevant code. Codebase may lack clear entry points, documentation, or conventional structure.",
228	    interpretation_friction:
229	      "Agent had to revise its approach, suggesting the task requirements or codebase patterns were initially misunderstood.",
230	    tooling_friction:
231	      "Tools failed or required retries. Build tools, tests, or development environment may need attention.",
232	    verification_friction:
233	      "Testing and validation took more effort than expected. Test setup, feedback loops, or CI may be slow or fragile.",
234	    boundary_friction:
235	      "Task touched many files/modules. Responsibilities may not be well-encapsulated, or the change is inherently cross-cutting.",
236	    spec_friction:
237	      "Task specification was ambiguous or incomplete, requiring the agent to make assumptions or seek clarification.",
238	    retrieval_friction:
239	      "Agent struggled to find specific information through search. Code organization or naming may not support efficient retrieval.",
240	  };
241	  return descriptions[category];
242	}
243	
