1	/**
2	 * CLI pretty-print renderer.
3	 *
4	 * Renders a Report as a colorful, readable terminal output.
5	 */
6	
7	import type { Report, FrictionItem, Recommendation, Evidence } from "../types/report.js";
8	
9	// ANSI color helpers (no dependencies needed)
10	const bold = (s: string) => `\x1b[1m${s}\x1b[0m`;
11	const dim = (s: string) => `\x1b[2m${s}\x1b[0m`;
12	const red = (s: string) => `\x1b[31m${s}\x1b[0m`;
13	const green = (s: string) => `\x1b[32m${s}\x1b[0m`;
14	const yellow = (s: string) => `\x1b[33m${s}\x1b[0m`;
15	const blue = (s: string) => `\x1b[34m${s}\x1b[0m`;
16	const magenta = (s: string) => `\x1b[35m${s}\x1b[0m`;
17	const cyan = (s: string) => `\x1b[36m${s}\x1b[0m`;
18	
19	export function renderCli(report: Report): string {
20	  const lines: string[] = [];
21	  const w = 60; // width for bars
22	
23	  lines.push("");
24	  lines.push(bold("  BEAVER SESSION ANALYSIS"));
25	  lines.push(dim(`  Generated ${report.metadata.generatedAt}`));
26	  lines.push(dim(`  Mode: ${report.metadata.analysisMode} | Provider: ${report.metadata.sessionProvider}`));
27	  lines.push("");
28	
29	  // ── Task Summary ──
30	  lines.push(sectionHeader("TASK SUMMARY"));
31	  for (const line of report.taskSummary.split("\n")) {
32	    lines.push(`  ${line}`);
33	  }
34	  lines.push("");
35	
36	  // ── Effort Breakdown ──
37	  lines.push(sectionHeader("EFFORT BREAKDOWN"));
38	  lines.push(effortBar("Exploration", report.effortBreakdown.exploration, blue, w));
39	  lines.push(effortBar("Implementation", report.effortBreakdown.implementation, green, w));
40	  lines.push(effortBar("Debugging", report.effortBreakdown.debugging, red, w));
41	  lines.push(effortBar("Verification", report.effortBreakdown.verification, yellow, w));
42	  lines.push("");
43	
44	  // ── Key Signals ──
45	  lines.push(sectionHeader("KEY SIGNALS"));
46	  const ks = report.keySignals;
47	  lines.push(`  Files read:     ${cyan(String(ks.filesRead))}`);
48	  lines.push(`  Files written:  ${cyan(String(ks.filesWritten))}`);
49	  lines.push(`  Searches:       ${cyan(String(ks.searches))}`);
50	  lines.push(`  Edits:          ${cyan(String(ks.edits))}`);
51	  lines.push(`  Retries:        ${ks.retries > 0 ? red(String(ks.retries)) : dim("0")}`);
52	  lines.push(`  Test runs:      ${cyan(String(ks.testRuns))}`);
53	  lines.push(`  Commands:       ${cyan(String(ks.commands))}`);
54	  if (ks.uniqueFilesTouched.length > 0) {
55	    lines.push(`  Unique files:   ${cyan(String(ks.uniqueFilesTouched.length))}`);
56	  }
57	  lines.push("");
58	
59	  // ── Friction Analysis ──
60	  lines.push(sectionHeader("FRICTION ANALYSIS"));
61	  lines.push(renderFrictionItem("PRIMARY", report.frictionAnalysis.primary));
62	  for (const secondary of report.frictionAnalysis.secondary) {
63	    lines.push(renderFrictionItem("SECONDARY", secondary));
64	  }
65	  lines.push("");
66	
67	  // ── Evidence ──
68	  if (report.evidence.length > 0) {
69	    lines.push(sectionHeader("EVIDENCE"));
70	    for (const ev of report.evidence.slice(0, 10)) {
71	      lines.push(renderEvidence(ev));
72	    }
73	    if (report.evidence.length > 10) {
74	      lines.push(dim(`  ... and ${report.evidence.length - 10} more`));
75	    }
76	    lines.push("");
77	  }
78	
79	  // ── Recommendations ──
80	  if (report.recommendations.length > 0) {
81	    lines.push(sectionHeader("RECOMMENDATIONS"));
82	    for (let i = 0; i < report.recommendations.length; i++) {
83	      lines.push(renderRecommendation(i + 1, report.recommendations[i]));
84	    }
85	    lines.push("");
86	  }
87	
88	  // ── Git Context ──
89	  if (report.gitContext.detected) {
90	    lines.push(sectionHeader("GIT CONTEXT"));
91	    lines.push(`  Type: ${report.gitContext.type}`);
92	    for (const repo of report.gitContext.repos) {
93	      lines.push(`  Repo: ${repo.path}`);
94	      if (repo.branch) lines.push(`  Branch: ${repo.branch}`);
95	      if (repo.hasUncommittedChanges) {
