1	/**
2	 * Heuristic chunk analysis.
3	 *
4	 * Analyzes each chunk without LLM calls, using pattern matching
5	 * and heuristics to detect friction and effort signals.
6	 */
7	
8	import type { Chunk, ChunkAnalysis, EffortSignal, FrictionCategory } from "../types/chunks.js";
9	import type {
10	  SessionEvent,
11	  FileReadEvent,
12	  FileWriteEvent,
13	  SearchEvent,
14	  RetryEvent,
15	  CommandRunEvent,
16	  TestRunEvent,
17	} from "../types/events.js";
18	
19	export function analyzeHeuristic(chunk: Chunk): ChunkAnalysis {
20	  const summary = generateSummary(chunk);
21	  const effortSignals = detectEffortSignals(chunk);
22	  const frictionClassification = detectFriction(chunk);
23	  const patterns = detectPatterns(chunk);
24	
25	  return {
26	    phase: chunk.phase,
27	    summary,
28	    effortSignals,
29	    frictionClassification,
30	    patterns,
31	    eventCount: chunk.events.length,
32	  };
33	}
34	
35	// --- Summary generation ---
36	
37	function generateSummary(chunk: Chunk): string {
38	  const counts = countEventTypes(chunk.events);
39	  const files = getUniqueFiles(chunk.events);
40	  const parts: string[] = [];
41	
42	  parts.push(`${chunk.phase} phase with ${chunk.events.length} events`);
43	
44	  if (counts.file_read > 0) parts.push(`${counts.file_read} file reads`);
45	  if (counts.file_write > 0) parts.push(`${counts.file_write} file writes`);
46	  if (counts.search > 0) parts.push(`${counts.search} searches`);
47	  if (counts.test_run > 0) parts.push(`${counts.test_run} test runs`);
48	  if (counts.retry > 0) parts.push(`${counts.retry} retries`);
49	  if (counts.command_run > 0) parts.push(`${counts.command_run} commands`);
50	
51	  if (files.length > 0) {
52	    parts.push(`across ${files.length} file(s)`);
53	  }
54	
55	  return parts.join(", ");
56	}
57	
58	// --- Effort signal detection ---
59	
60	function detectEffortSignals(chunk: Chunk): EffortSignal[] {
61	  const signals: EffortSignal[] = [];
62	  const counts = countEventTypes(chunk.events);
63	
64	  // High read count = lots of exploration
65	  if (counts.file_read > 5) {
66	    signals.push({
67	      type: "excessive_exploration",
68	      description: `Read ${counts.file_read} files — agent may have been unsure where to look`,
69	      weight: counts.file_read > 10 ? "high" : "medium",
70	    });
71	  }
72	
73	  // Many searches = difficulty finding things
74	  if (counts.search > 3) {
75	    signals.push({
76	      type: "search_heavy",
77	      description: `${counts.search} searches performed — codebase may lack discoverable structure`,
78	      weight: counts.search > 8 ? "high" : "medium",
79	    });
80	  }
81	
82	  // Retries = something went wrong
83	  if (counts.retry > 0) {
84	    signals.push({
85	      type: "retries_detected",
86	      description: `${counts.retry} retries detected — earlier attempts failed or were incomplete`,
87	      weight: counts.retry > 3 ? "high" : "medium",
88	    });
89	  }
90	
91	  // Repeated writes to same file
92	  const repeatedFiles = getRepeatedWriteFiles(chunk.events);
93	  if (repeatedFiles.length > 0) {
94	    signals.push({
95	      type: "repeated_edits",
96	      description: `Files edited multiple times: ${repeatedFiles.join(", ")}`,
97	      weight: "medium",
98	    });
99	  }
100	
101	  // Many test runs = possibly struggling with verification
102	  if (counts.test_run > 2) {
103	    signals.push({
104	      type: "test_heavy",
105	      description: `${counts.test_run} test runs — may indicate trial-and-error debugging`,
106	      weight: counts.test_run > 5 ? "high" : "medium",
107	    });
108	  }
109	
110	  // Plan revisions
111	  if (counts.plan_revision > 0) {
112	    signals.push({
113	      type: "plan_changes",
114	      description: `${counts.plan_revision} plan revision(s) — approach had to change mid-task`,
115	      weight: "high",
116	    });
117	  }
118	
119	  return signals;
120	}
121	
122	// --- Friction detection ---
123	
124	function detectFriction(chunk: Chunk): FrictionCategory[] {
125	  const frictions: FrictionCategory[] = [];
126	  const counts = countEventTypes(chunk.events);
127	
128	  // Discovery friction: lots of reads + searches
129	  if (counts.file_read + counts.search > 8) {
130	    frictions.push("discovery_friction");
131	  }
132	
133	  // Retrieval friction: many searches with possibly poor results
134	  if (counts.search > 5) {
135	    frictions.push("retrieval_friction");
136	  }
137	
138	  // Verification friction: many test runs or retries after tests
139	  if (counts.test_run > 2 || (counts.test_run > 0 && counts.retry > 0)) {
140	    frictions.push("verification_friction");
141	  }
142	
143	  // Tooling friction: retries on tool calls
144	  if (counts.retry > 2) {
145	    frictions.push("tooling_friction");
146	  }
147	
148	  // Interpretation friction: plan revisions indicate misunderstanding
149	  if (counts.plan_revision > 0) {
150	    frictions.push("interpretation_friction");
151	  }
152	
153	  // Boundary friction: if we see both reads and writes across many files
154	  const files = getUniqueFiles(chunk.events);
155	  if (files.length > 10) {
156	    frictions.push("boundary_friction");
157	  }
158	
159	  return frictions;
160	}
161	
162	// --- Pattern detection ---
163	
164	function detectPatterns(chunk: Chunk): string[] {
165	  const patterns: string[] = [];
166	  const counts = countEventTypes(chunk.events);
167	  const events = chunk.events;
168	
169	  // Read-then-search pattern (agent reading then searching = lost)
170	  const readSearchPairs = countSequentialPairs(events, "file_read", "search");
171	  if (readSearchPairs > 2) {
172	    patterns.push(
173	      `Read-then-search pattern (${readSearchPairs}x) — agent repeatedly read files then searched for more context`
174	    );
175	  }
176	
177	  // Edit-test-edit cycle (debugging loop)
178	  const editTestCycles = countEditTestCycles(events);
179	  if (editTestCycles > 1) {
180	    patterns.push(
181	      `Edit-test-edit cycle (${editTestCycles}x) — trial-and-error debugging loop`
182	    );
183	  }
184	
185	  // Broad exploration pattern
186	  const uniqueReadFiles = getUniqueFilesByType(events, "file_read");
187	  if (uniqueReadFiles.length > 8) {
188	    patterns.push(
189	      `Broad exploration — read ${uniqueReadFiles.length} different files (may indicate unclear entry point)`
190	    );
191	  }
192	
193	  // Focused implementation
194	  const writeFiles = getUniqueFilesByType(events, "file_write");
195	  if (writeFiles.length > 0 && writeFiles.length <= 3 && counts.file_write > 3) {
196	    patterns.push(
197	      `Focused implementation — ${counts.file_write} edits concentrated in ${writeFiles.length} file(s)`
198	    );
199	  }
200	
201	  // Scattered implementation
202	  if (writeFiles.length > 5) {
203	    patterns.push(
204	      `Scattered implementation — writes spread across ${writeFiles.length} files (may indicate cross-cutting change)`
205	    );
206	  }
207	
208	  return patterns;
209	}
210	
211	// --- Helpers ---
212	
213	function countEventTypes(
214	  events: SessionEvent[]
215	): Record<string, number> {
216	  const counts: Record<string, number> = {};
217	  for (const e of events) {
218	    counts[e.type] = (counts[e.type] || 0) + 1;
219	  }
220	  return counts;
221	}
222	
223	function getUniqueFiles(events: SessionEvent[]): string[] {
224	  const files = new Set<string>();
225	  for (const e of events) {
226	    const data = e.data as Record<string, unknown>;
227	    if (typeof data.path === "string" && data.path) {
228	      files.add(data.path);
229	    }
230	  }
231	  return Array.from(files);
232	}
233	
234	function getUniqueFilesByType(
235	  events: SessionEvent[],
236	  type: string
237	): string[] {
238	  const files = new Set<string>();
239	  for (const e of events) {
240	    if (e.type !== type) continue;
241	    const data = e.data as Record<string, unknown>;
242	    if (typeof data.path === "string" && data.path) {
243	      files.add(data.path);
244	    }
245	  }
246	  return Array.from(files);
247	}
248	
249	function getRepeatedWriteFiles(events: SessionEvent[]): string[] {
250	  const writeCounts = new Map<string, number>();
251	  for (const e of events) {
252	    if (e.type !== "file_write") continue;
253	    const path = (e.data as FileWriteEvent).path;
254	    if (path) {
255	      writeCounts.set(path, (writeCounts.get(path) || 0) + 1);
256	    }
257	  }
258	  return Array.from(writeCounts.entries())
259	    .filter(([, count]) => count > 1)
260	    .map(([path]) => path);
261	}
262	
263	function countSequentialPairs(
264	  events: SessionEvent[],
265	  typeA: string,
266	  typeB: string
267	): number {
268	  let count = 0;
269	  for (let i = 0; i < events.length - 1; i++) {
270	    if (events[i].type === typeA && events[i + 1].type === typeB) {
271	      count++;
272	    }
273	  }
274	  return count;
275	}
276	
277	function countEditTestCycles(events: SessionEvent[]): number {
278	  let cycles = 0;
279	  for (let i = 0; i < events.length - 2; i++) {
280	    if (
281	      events[i].type === "file_write" &&
282	      events[i + 1].type === "test_run" &&
283	      events[i + 2].type === "file_write"
284	    ) {
285	      cycles++;
286	    }
287	  }
288	  return cycles;
289	}
