+  try {
+    return JSON.parse(extracted) as T;
+  } catch (err) {
+    throw new LLMParseError(
+      `Failed to parse extracted JSON: ${(err as Error).message}. Snippet: ${extracted.slice(0, 200)}`
+    );
+  }
+}
+
+function stripCodeFences(s: string): string {
+  const fence = /^```(?:json)?\s*\n([\s\S]*?)\n```$/;
+  const m = s.match(fence);
+  return m ? m[1].trim() : s;
+}
+
+function extractBalancedJson(s: string): string | null {
+  const start = s.indexOf("{");
+  if (start < 0) return null;
+  let depth = 0;
+  let inStr = false;
+  let escape = false;
+  for (let i = start; i < s.length; i++) {
+    const ch = s[i];
+    if (escape) {
+      escape = false;
+      continue;
+    }
+    if (ch === "\\") {
+      escape = true;
+      continue;
+    }
+    if (ch === '"') {
+      inStr = !inStr;
+      continue;
+    }
+    if (inStr) continue;
+    if (ch === "{") depth++;
+    else if (ch === "}") {
+      depth--;
+      if (depth === 0) return s.slice(start, i + 1);
+    }
+  }
+  return null;
+}
+
+// --- Errors ---
+
+export class LLMConfigError extends Error {
+  constructor(message: string) {
+    super(message);
+    this.name = "LLMConfigError";
+  }
+}
+
+export class LLMAPIError extends Error {
+  status: number;
+  constructor(message: string, status: number) {
+    super(message);
+    this.name = "LLMAPIError";
+    this.status = status;
+  }
+}
+
+export class LLMParseError extends Error {
+  constructor(message: string) {
+    super(message);
+    this.name = "LLMParseError";
+  }
+}
+
+// --- Internals ---
+
+interface AnthropicMessagesResponse {
+  id?: string;
+  model?: string;
+  content?: Array<{ type: string; text?: string }>;
+  usage?: { input_tokens?: number; output_tokens?: number };
+  stop_reason?: string;
+}
+
+async function safeReadBody(res: Response): Promise<string> {
+  try {
+    return await res.text();
+  } catch {
+    return "<unreadable body>";
+  }
+}
+
+function isRetryable(err: unknown): boolean {
+  if (err instanceof LLMAPIError) return err.status >= 500 || err.status === 429;
+  // Network / abort errors are retryable.
+  if (err instanceof Error && (err.name === "AbortError" || err.name === "TypeError")) {
+    return true;
+  }
+  return false;
+}
+
+function backoffMs(attempt: number): number {
+  return 500 * Math.pow(2, attempt) + Math.floor(Math.random() * 250);
+}
+
+function sleep(ms: number): Promise<void> {
+  return new Promise((resolve) => setTimeout(resolve, ms));
+}

