1	/**
2	 * Minimal Anthropic Messages client.
3	 *
4	 * Uses native fetch — no SDK dependency. Designed to be tiny and replaceable.
5	 * Exposes a single `callLLM` function that takes a prompt and returns the
6	 * text response plus token usage metadata.
7	 */
8	
9	export interface LLMClientOptions {
10	  /** Anthropic API key. Defaults to env ANTHROPIC_API_KEY. */
11	  apiKey?: string;
12	  /** Model id. Defaults to claude-sonnet-4-6. */
13	  model?: string;
